class PostsSearch{constructor(){this.searchBox=document.getElementById("search-input"),this.searchBox.onkeyup=function(s){"Enter"==s.key&&this.searchPosts()}}searchPosts(){if(this.searchBox.value){let s=new URLSearchParams;s.set("tags",this.searchBox.value),location.href=`/posts/?${s.toString()}`}}}export{PostsSearch};